 using Microsoft.ML;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public sealed class TicketClassifierService
 {
     private readonly string _modelPath;
     private readonly string _dataPath;
     private readonly MLContext _mlContext;
     private readonly ILogger<TicketClassifierService> _logger;

     public TicketClassifierService(ILogger<TicketClassifierService> logger, IWebHostEnvironment env)
     {
         _mlContext = new MLContext(seed: 42);
         _logger = logger;
         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
     }

     public string ModelPath => _modelPath;

     /// <summary>
     /// Creates an initial model before DI is available (used at startup).
     /// </summary>
     public static void TrainInitialModel(string dataPath, string modelPath)
     {
         var mlContext = new MLContext(seed: 42);
         var data = mlContext.Data.LoadFromTextFile<TicketData>(
             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
         var pipeline = BuildPipeline(mlContext);
         var model = pipeline.Fit(data);
         mlContext.Model.Save(model, data.Schema, modelPath);
     }

     public TrainingResult TrainAndEvaluate()
     {
         var data = _mlContext.Data.LoadFromTextFile<TicketData>(
             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         var pipeline = BuildPipeline(_mlContext);

         var model = pipeline.Fit(data);

         _mlContext.Model.Save(model, data.Schema, _modelPath);
         _logger.LogInformation("Model saved to {Path}", _modelPath);

         var predictions = model.Transform(data);
         var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

         _logger.LogInformation(
             "Metrics — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
             metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

         return new TrainingResult
         {
             Message = "Model trained and saved successfully.",
             Metrics = new EvaluationMetrics
             {
                 MicroAccuracy = metrics.MicroAccuracy,
                 MacroAccuracy = metrics.MacroAccuracy,
                 LogLoss = metrics.LogLoss,
                 LogLossReduction = metrics.LogLossReduction
             }
         };
     }
 }

